import{_ as e,c as o,o as n,a4 as i}from"./chunks/framework.C7hkbLDc.js";const u=JSON.parse('{"title":"1.2 Operation Permissions","description":"","frontmatter":{},"headers":[],"relativePath":"en/1-python/1-intro/1.2-permission.md","filePath":"en/1-python/1-intro/1.2-permission.md"}'),a={name:"en/1-python/1-intro/1.2-permission.md"};function s(r,t,h,c,d,p){return n(),o("div",{"data-pagefind-body":!0},t[0]||(t[0]=[i('<h1 id="1-2" tabindex="-1">1.2 Operation Permissions <a class="header-anchor" href="#1-2" aria-label="Permalink to “1.2 Operation Permissions”">​</a></h1><p>To use the SDK, the host computer must have obtained the operation permissions.</p><p>If a teach pendant is connected to the IRC - I4A - C series control cabinet, you must switch the teach pendant to the automatic mode. Then the host computer can connect to the control cabinet and obtain the operation permissions by calling the <code>acquire_access</code> method of the SDK. After the host computer gains the operation permissions, the teach pendant loses its operation permissions. At this time, the PC status light will turn green, and the TP status indicator light will be off. If the teach pendant is in manual mode, the host computer cannot obtain the permissions, and the teach pendant has the operation permissions.</p><p>If no teach pendant is connected to the IRC - I4A - C series control cabinet, the host computer can directly connect to the IRC - I4A - C series control cabinet to obtain the operation permissions.</p><table tabindex="0"><thead><tr><th>System Status Indicators and Buttons</th><th>Function</th></tr></thead><tbody><tr><td>TP Status Light</td><td>When a teach pendant is connected to the control cabinet, this light turns green; otherwise, it is off.</td></tr><tr><td>PC Status Light</td><td>When operating with the virtual teach pendant software Compass, this light turns green; otherwise, it is off.</td></tr><tr><td>AUTO Status Light</td><td>When the robot is in automatic operation mode or neither the teach pendant nor Compass has control, this light turns green; otherwise, it is off.</td></tr><tr><td>TP BYPASS Button</td><td>If the robot is in manual mode before unplugging the teach pendant, you can press and hold this button after unplugging the teach pendant to switch the robot to automatic mode.</td></tr></tbody></table>',5)]))}const l=e(a,[["render",s]]);export{u as __pageData,l as default};
